    const metas = obj.metas || [];
    const metasConcluidas = metas.filter(function(m) { return m.objetivo_completo; }).length;
    const proximaMeta = metas.find(function(m) { return !m.objetivo_completo; });
    let t = '- ' + obj.objetivo_descricao + ' | ' + metasConcluidas + '/' + metas.length + ' metas concluídas';
    if (!obj.primeiro_aporte_feito) {
      t += ' | Aguardando primeiro aporte';
    } else if (proximaMeta) {
      t += ' | Próxima meta: ' + brl(proximaMeta.objetivo_investir) + ' até ' + fmtDate(proximaMeta.data_limite) + ' (investido: ' + brl(proximaMeta.saldo_alocado) + ')';
    } else {
      t += ' | Todas as metas concluídas!';
    }
    return t;
  }).join('\n');
}

const ultimosDepositos = depositos.map(function(d) {
  return '- ' + fmtDate(d.data_criacao) + ': ' + brl(d.valor_deposito) + ' (' + d.status_deposito + ')';
}).join('\n') || 'Nenhum depósito recente.';

const ultimosSaques = saques.map(function(s) {
  return '- ' + fmtDate(s.data_criacao) + ': ' + brl(s.valor_saque) + ' (' + s.status_saque + ')';
}).join('\n') || 'Nenhum saque recente.';


const mesesPT = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];
const rendimentosStr = rendimentos.length > 0
  ? rendimentos.map(function(r) {
      const parts = r.mes.split('-');
      const mesNome = mesesPT[parseInt(parts[1], 10) - 1];
      return '- ' + mesNome + '/' + parts[0] + ': ' + brl(r.rendimento_mensal);
    }).join('\n')
  : 'Nenhum rendimento registrado ainda.';
const totalRendimento = rendimentos.reduce(function(acc, r) { return acc + parseFloat(r.rendimento_mensal || 0); }, 0);
const totalRendimentoStr = rendimentos.length > 0 ? '\nTotal acumulado: ' + brl(totalRendimento) : '';

const novoContexto = 'Apelido: ' + (u.apelido || 'usuário') + '\n' +
  'Liga: ' + (u.liga || '-') + ' | Posição: #' + (u.posicao || '-') + ' | Pontos: ' + (u.pontos || 0) + '\n' +
  'Total investido: ' + brl(u.investido) + '\n\n' +
  'Objetivos:\n' + objLines + '\n\n' +
  'Últimos depósitos:\n' + ultimosDepositos + '\n\n' +
  'Últimos saques:\n' + ultimosSaques + '\n\n' +
  'Rendimentos mensais:\n' + rendimentosStr + totalRendimentoStr;

const staticData = $getWorkflowStaticData('global');
const sessions = staticData.waSessions || {};
if (sessions['wa_' + phone]) {
  sessions['wa_' + phone].contexto = novoContexto;
  try {
    if (objetivos.length > 0) {
      const obj = objetivos[0];
      const pendentes = (obj.metas || []).filter(function(m) { return !m.objetivo_completo; });
      if (pendentes.length > 0 && obj.primeiro_aporte_feito) {
        const pm = pendentes[0];
        const resto = parseFloat(pm.objetivo_investir) - parseFloat(pm.saldo_alocado);
        if (resto > 0) sessions['wa_' + phone].proximaMetaValor = resto.toFixed(2);
        else delete sessions['wa_' + phone].proximaMetaValor;
      } else {
        delete sessions['wa_' + phone].proximaMetaValor;
      }
    }
  } catch(e) {}
  staticData.waSessions = sessions;
}

const msgPix = $('Montar Msg Pix').first().json;
return [{ json: { output: msgPix.output, pixUrl: msgPix.pixUrl, remoteJid: msgPix.remoteJid } }];

