const body = $input.first().json.body;
const celular = String(body.celular).replace(/\D/g, '');
const usuarioId = body.usuario_id;
const staticData = $getWorkflowStaticData('global');
const sessions = staticData.waSessions || {};
if (!sessions['wa_' + celular]) sessions['wa_' + celular] = {};
sessions['wa_' + celular].depositStep = 'sem_objetivo_confirm';
sessions['wa_' + celular].usuarioId = usuarioId;
staticData.waSessions = sessions;
return [{ json: { ok: true } }];

const prev = $('Lógica Depósito WA').first().json;
const { objData, usuarioId, phone, sessionId } = prev;
const staticData = $getWorkflowStaticData('global');
const sessions = staticData.waSessions || {};
const remoteJid = $('Extrair Dados WA').first().json.remoteJid;

function brl(v) {
  const p = parseFloat(v || 0).toFixed(2).split('.');
  p[0] = p[0].replace(/\B(?=(\d{3})+(?!\d))/g, '.');
  return 'R$ ' + p[0] + ',' + p[1];
}

if (sessions['wa_' + phone]) {
  delete sessions['wa_' + phone].objData;
  staticData.waSessions = sessions;
}

const aporte  = parseFloat(objData.aporte  || 0);
const parcela = parseFloat(objData.parcela || 0);

if (aporte > 0) {
  return [{ json: { callPix: true, pixValue: aporte.toFixed(2), usuarioId, phone, sessionId, remoteJid,
    successMsg: '🎉 Objetivo criado com sucesso!\n\nAgora vou gerar o Pix do seu aporte inicial:' } }];
}

if (sessions['wa_' + phone]) {
  sessions['wa_' + phone].depositStep = 'obj_parcela_pix';
  sessions['wa_' + phone].parcelaValor = parcela.toFixed(2);
  staticData.waSessions = sessions;
}

const output = '🎉 Objetivo criado com sucesso!\n\n' +
  'Quer pagar a parcela deste mês de ' + brl(parcela) + ' agora?\n\n' +
  'Responda _*sim*_ para criar o Pix ou _*não*_ para deixar para depois.';
return [{ json: { callPix: false, output, remoteJid } }];

const pix  = $input.first().json;
const prev = $('Após Criar Objetivo').first().json;
const remoteJid  = prev.remoteJid;
const successMsg = prev.successMsg || '🎉 Objetivo criado!';

function brl(v) {
  const p = parseFloat(v || 0).toFixed(2).split('.');
  p[0] = p[0].replace(/\B(?=(\d{3})+(?!\d))/g, '.');
  return 'R$ ' + p[0] + ',' + p[1];
}

if (!pix.pixCopiaECola) {
  return [{ json: { output: successMsg + '\n\nMas não consegui gerar o Pix agora. Tente mais tarde.', pixCode: null, remoteJid } }];
}

const output = successMsg + '\n\nPix de ' + brl(prev.pixValue) + ' gerado! 💸\n\nAcesse o link abaixo para copiar o código Pix:';
return [{ json: { output, pixCode: pix.pixCopiaECola, remoteJid } }];
